ModelMonitor::ModelMonitor(InferenceEngine* engine, QWidget* parent)
    : QWidget(parent), m_engine(engine)
{
    QVBoxLayout* lay = new QVBoxLayout(this);
    m_memLabel   = new QLabel("Memory: --", this);
