GGUFLoader::GGUFLoader(const QString& path) {
    file.setFileName(path);
    if (!file.open(QIODevice::ReadOnly)) {
        qWarning() << "Failed to open GGUF file:" << path;
        return;
    }
    
    QDataStream ds(&file);
    ds.setByteOrder(QDataStream::LittleEndian);
    
    // Read GGUF header
    ds.readRawData(head.magic, 4);
    ds >> head.version >> head.tensorCount >> head.metadataSize;
    
    if (strncmp(head.magic, "GGUF", 4) != 0) {
        qWarning() << "Invalid GGUF magic:" << QString::fromLatin1(head.magic, 4);
        file.close();
        return;
    }
    
    // Read tensor offsets
    for (quint64 i = 0; i < head.tensorCount; ++i) {
        quint32 nameLen;
        ds >> nameLen;
        QByteArray nameBytes(nameLen, Qt::Uninitialized);
        ds.readRawData(nameBytes.data(), nameLen);
        QString name = QString::fromUtf8(nameBytes);
        
        quint64 offset;
        ds >> offset;
        offsetMap.insert(name, offset);
    }
}

QByteArray GGUFLoader::inflateWeight(const QString& tensorName) {
    if (!offsetMap.contains(tensorName)) {
        qWarning() << "Tensor not found:" << tensorName;
        return QByteArray();
    }
    
    quint64 offset = offsetMap.value(tensorName);
    if (!file.seek(offset)) {
        qWarning() << "Failed to seek to tensor:" << tensorName;
        return QByteArray();
    }
    
    QDataStream ds(&file);
    ds.setByteOrder(QDataStream::LittleEndian);
    
    // Read tensor header
    quint32 nDims;
    ds >> nDims;
    
    QVector<quint64> shape(nDims);
    for (quint32 i = 0; i < nDims; ++i) {
        ds >> shape[i];
    }
    
    quint32 type;
    ds >> type;
    
    // Calculate tensor size
    quint64 elementCount = 1;
    for (quint64 dim : shape) {
        elementCount *= dim;
    }
    
    quint64 elementSize = 0;
    switch (type) {
        case 0: elementSize = 4; break; // F32
        case 1: elementSize = 2; break; // F16
        case 2: elementSize = 18; break; // Q4_0
        case 3: elementSize = 20; break; // Q4_1
        case 10: elementSize = 24; break; // Q4_K
        default: elementSize = 4; break;
    }
    
    quint64 rawSize = elementCount * elementSize;
    
    // Check for compression
    quint8 compressionType;
    ds >> compressionType;
    
    if (compressionType == 0) {
        // No compression - read raw data
        QByteArray data(rawSize, Qt::Uninitialized);
        ds.readRawData(data.data(), rawSize);
        return data;
    } else if (compressionType == 1) {
        // DEFLATE compression - use MASM decompression
        quint64 compressedSize;
        ds >> compressedSize;
        
        QByteArray compressed(compressedSize, Qt::Uninitialized);
        ds.readRawData(compressed.data(), compressedSize);
        
        // Use MASM decompression
        QByteArray decompressed(rawSize, Qt::Uninitialized);
        size_t outSize = rawSize;
        
        inflate_brutal_masm(
            reinterpret_cast<const unsigned char*>(compressed.constData()),
            compressedSize,
            reinterpret_cast<unsigned char*>(decompressed.data()),
            &outSize
        );
        
        if (outSize != rawSize) {
            qWarning() << "Decompression size mismatch for tensor:" << tensorName;
            return QByteArray();
        }
        
        return decompressed;
    }
    
    qWarning() << "Unsupported compression type:" << compressionType;
    return QByteArray();
}

